const purchases = $input.all();

const yahooMap = {
  'APC': 'APC.F', 'AMZ': 'AMZ.F', 'NVD': 'NVD.F', 'AP2': 'AP2.DE', 'MSF': 'MSF.F',
  'TL0': 'TL0.DE', 'TLO': 'TL0.DE', 'TKE': 'TKE.F', 'M4I': 'M4I.F', 'ABEA': 'ABEA.F',
  'CSPX': 'CSPX.AS', 'CNDX': 'CNDX.AS', '3ZU0': '3ZU0.F', '1170': '1170.F',
  '9D5': '9D5.F', 'GXG': 'GXG.F', 'BKSY': 'BKSY',
  'GOLD-ETFP': 'GOLD-EUR.PA',
  'AL2SI': 'AL2SI.PA', 'SU': 'SU.PA', 'ESE': 'ESE.PA',
  'EUEA': 'EUEA.AS', 'STEC': 'STEC.AS', 'ALRIB': 'ALRIB.PA',
  'SOI': 'SOI.PA', 'BTC': 'BTC-EUR'
};

const netQty = {};
const nameMap = {};
for (const item of purchases) {
    const ticker = (item.json.ticker || '').toUpperCase().trim();
    const qty = parseFloat(item.json.quantity) || 0;
    if (!ticker || ticker.startsWith('CASH-')) continue;
    netQty[ticker] = (netQty[ticker] || 0) + qty;
    if (!nameMap[ticker]) nameMap[ticker] = item.json.name || ticker;
}

const seen = new Set();
const results = [];
for (const [ticker, qty] of Object.entries(netQty)) {
    if (qty < 0.01) continue;
    const yahooTicker = yahooMap[ticker] || ticker;
    if (seen.has(yahooTicker)) continue;
    seen.add(yahooTicker);
    const name = nameMap[ticker] || ticker;
    results.push({ json: { yahooTicker, name } });
}

return results;

const httpResponses = $input.all();
const tickerItems = $('Build Ticker List').all();

const now = Math.floor(Date.now() / 1000);
const allEvents = [];
const seenUUIDs = new Set();

for (let i = 0; i < httpResponses.length; i++) {
    const resp = httpResponses[i].json;
    const tickerInfo = tickerItems[i] ? tickerItems[i].json : {};
    const yahooTicker = tickerInfo.yahooTicker || '';
    const name = tickerInfo.name || yahooTicker;

    let calEvents = null;
    let summaryDetail = null;
    try {
        const result = resp.quoteSummary && resp.quoteSummary.result;
        calEvents = result && result[0] && result[0].calendarEvents;
        summaryDetail = result && result[0] && result[0].summaryDetail;
    } catch(e) {}

    if (!calEvents) continue;

    const dividendRate = summaryDetail && summaryDetail.dividendRate && summaryDetail.dividendRate.raw;

    // Earnings dates
    const earningsDates = (calEvents.earnings && calEvents.earnings.earningsDate) || [];
    for (let j = 0; j < earningsDates.length; j++) {
        const ts = earningsDates[j].raw || 0;
        if (!ts) continue;
        const daysUntil = Math.floor((ts - now) / 86400);
        if (daysUntil < 1 || daysUntil > 7) continue;
        const dateStr = new Date(ts * 1000).toISOString().split('T')[0];
        const uuid = yahooTicker + '_earnings_' + dateStr;
        if (seenUUIDs.has(uuid)) continue;
        seenUUIDs.add(uuid);
        allEvents.push({ uuid, type: 'earnings', ticker: yahooTicker, name, date: ts, daysUntil, dateStr });
        break;
    }

    // Ex-dividend date (calendarEvents en priorité, summaryDetail en fallback)
    const exDiv = calEvents.exDividendDate || (summaryDetail && summaryDetail.exDividendDate);
    if (exDiv && exDiv.raw) {
        const ts = exDiv.raw;
        const daysUntil = Math.floor((ts - now) / 86400);
        if (daysUntil >= 1 && daysUntil <= 7) {
            const dateStr = new Date(ts * 1000).toISOString().split('T')[0];
            const uuid = yahooTicker + '_dividend_' + dateStr;
            if (!seenUUIDs.has(uuid)) {
                seenUUIDs.add(uuid);
                allEvents.push({ uuid, type: 'dividend', ticker: yahooTicker, name, date: ts, daysUntil, dateStr, dividendRate: dividendRate || null });
            }
        }
    }
}

allEvents.sort((a, b) => a.daysUntil - b.daysUntil);
return [{ json: { events: allEvents, count: allEvents.length, hasEvents: allEvents.length > 0 } }];

const data = $('Parse Events').first().json;
const sentDoc = $input.first().json || {};

const sentIds = new Set(sentDoc.ids || []);
const events = data.events || [];

const newEvents = events.filter(function(item) { return !sentIds.has(item.uuid); });

return [{ json: {
    hasEvents: newEvents.length > 0,
    events: newEvents,
    count: newEvents.length,
    existingSentIds: sentDoc.ids || []
}}];

const { events } = $input.first().json;

const NL = '\n';
function esc(s) { return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }

const earningsEvents = events.filter(function(e) { return e.type === 'earnings'; });
const dividendEvents = events.filter(function(e) { return e.type === 'dividend'; });

const lines = [];

if (earningsEvents.length > 0) {
    lines.push('<b>&#128197; R\u00e9sultats trimestriels</b>');
    for (const ev of earningsEvents) {
        const dayWord = ev.daysUntil === 1 ? 'demain' : 'dans ' + ev.daysUntil + ' j';
        lines.push('  &#128204; <b>' + esc(ev.name) + '</b> \u00b7 ' + dayWord + ' (' + ev.dateStr + ')');
    }
}

if (dividendEvents.length > 0) {
    if (lines.length > 0) lines.push('');
    lines.push('<b>&#128176; Ex-dates dividendes</b>');
    for (const ev of dividendEvents) {
        const dayWord = ev.daysUntil === 1 ? 'demain' : 'dans ' + ev.daysUntil + ' j';
        let line = '  &#128204; <b>' + esc(ev.name) + '</b> \u00b7 ' + dayWord + ' (' + ev.dateStr + ')';
        if (ev.dividendRate) line += ' \u00b7 ' + ev.dividendRate.toFixed(2) + '/action';
        lines.push(line);
    }
}

const header = '&#128276; <b>Agenda Portfolio</b> \u00b7 ' + events.length + ' \u00e9v\u00e9nement(s)';
const message = header + NL + NL + lines.join(NL);
const selectedUUIDs = events.map(function(e) { return e.uuid; });

return [{ json: { chatId: '2089017736', message, selectedUUIDs } }];

const { existingSentIds } = $('Filter Unsent').first().json;
const { selectedUUIDs } = $('Format Message').first().json;
const allSentIds = [...(existingSentIds || []), ...(selectedUUIDs || [])].slice(-500);
return [{ json: { ids: allSentIds } }];
